// sanitizeAndFormat takes raw user content, escapes all HTML, then applies
// a small set of safe formatting transformations (bold, italic, underline).
// This ensures no user-supplied HTML tags survive, only our generated tags.
func sanitizeAndFormat(raw string) template.HTML {
	// Step 1: HTML-escape the entire content to neutralize any injected HTML/JS.
	escaped := template.HTMLEscapeString(raw)

	// Step 2: Apply basic formatting on the escaped string.
	// Since the string is fully escaped, the **...** patterns cannot contain
	// malicious HTML — any angle brackets or quotes are already escaped entities.

	// Bold: **text**
	escaped = applyFormatting(escaped, "**", "<strong>", "</strong>")
	// Italic: *text* (but not **)
	escaped = applyItalicFormatting(escaped)
	// Underline: __text__
	escaped = applyFormatting(escaped, "__", "<u>", "</u>")
	// Newlines to <br>
	escaped = strings.ReplaceAll(escaped, "\n", "<br>")

	return template.HTML(escaped)
}

// applyFormatting replaces pairs of a delimiter with open/close HTML tags.
func applyFormatting(s, delimiter, openTag, closeTag string) string {
	var result strings.Builder
	parts := strings.Split(s, delimiter)
	for i, part := range parts {
		if i == 0 {
			result.WriteString(part)
			continue
		}
		// Odd-indexed splits get opening tag, even-indexed get closing tag
		if i%2 == 1 {
			result.WriteString(openTag)
		} else {
			result.WriteString(closeTag)
		}
		result.WriteString(part)
	}
	// If we have an unclosed tag (odd number of delimiters), close it
	if len(parts)%2 == 0 {
		result.WriteString(closeTag)
	}
	return result.String()
}

// applyItalicFormatting handles *text* while avoiding **text** (already processed).
// After bold processing, <strong> tags replaced **, so single * remaining are italic.
func applyItalicFormatting(s string) string {
	var result strings.Builder
	parts := strings.Split(s, "*")
	for i, part := range parts {
		if i == 0 {
			result.WriteString(part)
			continue
		}
		if i%2 == 1 {
			result.WriteString("<em>")
		} else {
			result.WriteString("</em>")
		}
		result.WriteString(part)
	}
	if len(parts)%2 == 0 {
		result.WriteString("</em>")
	}
	return result.String()
}

