func commentsHandler(w http.ResponseWriter, r *http.Request) {
	// Build safe view models: author is auto-escaped by the template engine
	// (it's a plain string), content is sanitized then formatted by us.
	safeComments := make([]SafeComment, len(comments))
	for i, c := range comments {
		safeComments[i] = SafeComment{
			// Author remains a plain string — html/template auto-escapes it.
			Author:    c.Author,
			Content:   sanitizeAndFormat(c.Content),
			Timestamp: c.Timestamp,
		}
	}

	w.Header().Set("Content-Type", "text/html; charset=utf-8")
	if err := tmpl.Execute(w, safeComments); err != nil {
		http.Error(w, "Internal Server Error", http.StatusInternalServerError)
	}
}

